from relay_protocol.gateway import EventGateway


def collect(receiver, chunks):
    events = []
    for chunk in chunks:
        events.extend(receiver.feed(chunk))
    return events


def test_one_byte_chunks_preserve_empty_and_zero_metadata():
    sender = EventGateway()
    receiver = EventGateway()
    event = {
        "type": "audit",
        "body": {"region": "\u6771\u4eac", "sequence": 0},
        "attempt": 0,
        "durable": False,
    }
    wire = sender.outbound(event)
    assert collect(receiver, (wire[index : index + 1] for index in range(len(wire)))) == [
        event
    ]


def test_fragmented_then_coalesced_frames_keep_message_boundaries():
    sender = EventGateway()
    receiver = EventGateway()
    first = {"type": "note", "body": {"text": "caf\u00e9"}, "trace": ""}
    second = {"type": "note", "body": {"text": "plain"}, "durable": False}
    third = {"type": "note", "body": {"text": "\U0001f680"}, "attempt": 3}
    combined = sender.outbound(first) + sender.outbound(second) + sender.outbound(third)
    cuts = (combined[:5], combined[5:19], combined[19:])
    assert collect(receiver, cuts) == [first, second, third]
